const r = await tools.exec_command({
  cmd: "sed -n '1,240p' [REDACTED_LOCAL_PATH]",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 20000
});
text(r.output);

const tasks = [
  tools.exec_command({
    cmd: "git rev-parse --show-toplevel && git rev-parse origin/main && git show -s --format='%H %cI %ct' origin/main && git status --short --branch",
    workdir: "[REDACTED_LOCAL_PATH]",
    yield_time_ms: 10000,
    max_output_tokens: 5000
  }),
  tools.exec_command({
    cmd: "rg --files '[REDACTED_LOCAL_PATH]'",
    workdir: "[REDACTED_LOCAL_PATH]",
    yield_time_ms: 10000,
    max_output_tokens: 20000
  }),
  tools.exec_command({
    cmd: "git ls-tree -r -l origin/main | awk 'END{print NR}' && git ls-tree -r -l origin/main | awk '{s+=$4} END{printf \"bytes=%d\\n\",s}'",
    workdir: "[REDACTED_LOCAL_PATH]",
    yield_time_ms: 10000,
    max_output_tokens: 2000
  })
];
const results = await Promise.all(tasks);
results.forEach((r,i)=>text(`---${i+1}---\n${r.output}`));

const r = await tools.exec_command({
  cmd: "wc -lc README_先读我.md 01_Codex整合任务包_v1.2.1.md 02_Roadmap_16Stage_Phase_Task.md 05_交接合并与版本谱系.md 06_全仓清理与真相源收敛规范.md 10_开发门禁停止回滚与发布协议.md 11_最终验收与恢复演练.md machine/deletion_candidate_schema.json machine/cleanup_policy.json machine/file_scope_manifest.json machine/stage_gate_matrix.csv machine/acceptance_matrix.csv machine/requirements_traceability.csv",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 5000
});
text(r.output);

const cmds = [
  "sed -n '1,220p' README_先读我.md",
  "sed -n '1,240p' 01_Codex整合任务包_v1.2.1.md",
  "sed -n '1,160p' 05_交接合并与版本谱系.md",
  "sed -n '1,180p' 06_全仓清理与真相源收敛规范.md",
  "sed -n '1,180p' machine/deletion_candidate_schema.json",
  "sed -n '1,160p' machine/cleanup_policy.json"
];
const results = await Promise.all(cmds.map(cmd => tools.exec_command({
  cmd,
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 12000
})));
results.forEach((r,i)=>text(`---DOC${i+1}---\n${r.output}`));

