const r = await tools.exec_command({
  cmd: "git -c gc.auto=0 ls-tree -r -l --full-tree origin/main | awk 'BEGIN{n=0;s=0} {n++; if ($4 ~ /^[0-9]+$/) s+=$4} END{printf \"tracked_files=%d\\ntracked_bytes=%0.f\\n\",n,s}'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 30000,
  max_output_tokens: 2000
});
text(JSON.stringify(r));

const r = await tools.exec_command({
  cmd: "ps -axo pid,ppid,etime,state,command | rg '(^| )95806|git.*ls-tree|git.*gc|git.*pack|awk.*tracked_files' | head -40",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 5000
});
text(r.output);

const r = await tools.exec_command({
  cmd: "git -c gc.auto=0 ls-tree -r --name-only origin/main | wc -l",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 2000
});
text(JSON.stringify(r));

const r = await tools.exec_command({
  cmd: "git -c gc.auto=0 ls-tree -r -z origin/main | ruby -rjson -0 -ne 'BEGIN{@rows=[]}; m=$_.match(/\\A(\\d+) (\\w+) ([0-9a-f]+)\\t(.*)\\z/m); @rows << [m[4],m[3]] if m; END{ pats={taskpac[REDACTED_LOCAL_PATH] ]?\\d+|phase[-_ ]?\\d+|stage|stages|evidence|run[-_ ]?(?:log|record|report))(?=\\/|[-_. ])/i,repor[REDACTED_LOCAL_PATH] raw=->(p){p.match?(%r{(^|/)(raw|public_raw|raw_archives|session_history)(/|$)}i)}; top=Hash.new(0); @rows.each{|p,h| top[p.split(%r{/},2)[0]]+=1}; out={total:@rows.length,top_level:top.sort_by{|k,v|[-v,k]}.to_h}; pats.each{|k,re| a=@rows.select{|p,h| !raw[p] && p.match?(re)}; out[k]={count:a.length,representatives:a.sort_by{|p,h|p}.first(35).map{|p,h|{path:p,blob:h}}}}; out[:raw_protected_count]=@rows.count{|p,h|raw[p]}; puts JSON.pretty_generate(out)}'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 30000
});
text(r.output);

