const r = await tools.exec_command({
  cmd: "git -c gc.auto=0 ls-tree -r -z origin/main | ruby -rjson -0 -ne 'BEGIN{@rows=[]};r=$_.delete_suffix(\"\\0\");m=r.match(/\\A\\d+ \\w+ ([0-9a-f]+)\\t(.*)\\z/m);@rows<<[m[2],m[1]] if m;END{ raw=->(p){p.match?(%r{(^|/)(raw|public_raw|raw_archives|session_history)(/|$)}i)}; cand=->(p){p.match?(%r{(^|/)(task.?packs?|handoffs?|stage_artifacts?|FINAL_ACCEPTANCE_BUNDLE|docs/(?:reviews|acceptance)|人类可读|机器治理/证据与日志|reports|artifacts|outputs|archive|legacy)(/|$)}i)}; rows=@rows.reject{|p,h|raw[p]}; dh=rows.group_by{|p,h|h}.select{|h,a|a.length>1 && h!=\"e69de29bb2d1d6434b8b29ae775ad8c2e48c5391\"}; rel=dh.select{|h,a|a.any?{|p,_|cand[p]}}; stem=Hash.new{|h,k|h[k]=[]}; rows.each{|p,h|next unless cand[p]; d=File.dirname(p);b=File.basename(p); b=b.sub(/\\.(?:tar\\.gz|jsonl|sqlite3\\.gz|[A-Za-z0-9]+)\\z/i,\"\");stem[[d,b]]<<[p,h]}; sg=stem.select{|k,a|a.map{|p,h|File.extname(p).downcase}.uniq.length>1 && a.length>1}; out={duplicate_blob_clusters_all:dh.length,duplicate_blob_paths_all:dh.values.sum(&:length),redundant_copies_all:dh.values.sum{|a|a.length-1},candidate_related_duplicate_clusters:rel.length,candidate_related_duplicate_paths:rel.values.sum(&:length),candidate_related_redundant_copies:rel.values.sum{|a|a.length-1},representative_duplicate_clusters:rel.sort_by{|h,a|[-a.length,h]}.first(25).map{|h,a|{blob:h,count:a.length,paths:a.map(&:first).sort.first(12)}},same_stem_multiformat_groups:sg.length,same_stem_multiformat_paths:sg.values.sum(&:length),representative_multiformat_groups:sg.sort_by{|k,a|[-a.length,k.join(\"/\")]}.first(25).map{|k,a|{stem:k.join(\"/\"),count:a.length,paths:a.map(&:first).sort}}};puts JSON.pretty_generate(out)}'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 25000
});
text(r.output);

