const r = await tools.exec_command({
  cmd: "git -c gc.auto=0 ls-tree -r -z origin/main OpenAIDatabase | ruby -rjson -0 -ne 'BEGIN{@r=[]};r=$_.delete_suffix(\"\\0\");m=r.match(/\\A\\d+ \\w+ ([0-9a-f]+)\\t(.*)\\z/m);@r<<[m[2],m[1]] if m;END{ raw=->(p){p.match?(%r{(^|/)(raw|public_raw|raw_archives|session_history)(/|$)}i)}; h=@r.reject{|p,x|raw[p]}.group_by{|p,x|x}.select{|x,a|a.length>1}; out={clusters:h.length,paths:h.values.sum(&:length),redundant:h.values.sum{|a|a.length-1},clusters_detail:h.sort_by{|x,a|[-a.length,x]}.map{|x,a|{blob:x,count:a.length,paths:a.map(&:first).sort}}};puts JSON.pretty_generate(out)}'",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 10000,
  max_output_tokens: 12000
});
text(r.output);

