#!/usr/bin/env python3
"""Generate S02-P1 read-only repository inventory reports.

The script never reads raw/session-history blob contents.  It consumes the
GitHub recursive tree response, an unquoted `git ls-tree` export, and a
path-only Git history export.  Content reads are restricted to non-raw package
manifests, workflows, validators, and selected large text/code files needed for
maintenance-cost estimates.
"""

from __future__ import annotations

import argparse
import collections
import datetime as dt
import hashlib
import json
import os
import re
import subprocess
import urllib.parse
from pathlib import Path, PurePosixPath
from typing import Any


TEXT_EXTENSIONS = {
    ".cjs", ".css", ".html", ".js", ".json", ".jsonl", ".jsx", ".md",
    ".mjs", ".py", ".sh", ".sql", ".toml", ".ts", ".tsx", ".txt",
    ".yaml", ".yml",
}
CODE_EXTENSIONS = {
    ".cjs", ".css", ".html", ".js", ".jsx", ".mjs", ".py", ".sh",
    ".sql", ".ts", ".tsx",
}
OWNER_FILENAMES = {
    "AGENTS.md", "README.md", "VERSION", "功能清单.md", "开发记录.md",
    "模型参数文件.md",
}
ALLOWED_CATEGORIES = {"keep", "merge", "delete", "regenerate", "migrate"}
ALLOWED_APPROVALS = {"pending", "approved", "rejected"}
REQUIRED_CANDIDATE_FIELDS = {
    "path", "category", "references", "runtime_dependency",
    "replacement_source", "reason", "restore_method", "batch",
    "validation", "approval",
}


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser()
    parser.add_argument("--repo", type=Path, required=True)
    parser.add_argument("--ref", default="origin/main")
    parser.add_argument("--github-tree", type=Path, required=True)
    parser.add_argument("--git-tree", type=Path, required=True)
    parser.add_argument("--history", type=Path, required=True)
    parser.add_argument("--out", type=Path, required=True)
    parser.add_argument("--github-repo", default="LinzeColin/CodexProject")
    return parser.parse_args()


def run_git(repo: Path, *args: str, text: bool = True) -> str | bytes:
    env = os.environ.copy()
    env["GIT_NO_LAZY_FETCH"] = "1"
    completed = subprocess.run(
        ["git", "-c", "core.quotepath=false", *args],
        cwd=repo,
        env=env,
        check=True,
        capture_output=True,
        text=text,
    )
    return completed.stdout


def is_raw_append_only_or_session_path(path: str) -> bool:
    low = "/" + path.lower().strip("/") + "/"
    protected_fragments = (
        "/data/raw/", "/data/raw_archives/", "/data/public_raw/",
        "/raw/", "/raw_archives/", "/public_raw/", "/session_history/",
        "/sessions_history/", "/private_imports/", "/private_exports/",
    )
    return any(fragment in low for fragment in protected_fragments)


def is_raw_or_session_path(path: str) -> bool:
    if is_raw_append_only_or_session_path(path):
        return True
    for segment in path.lower().split("/"):
        if re.search(r"(^raw$|^raw[_-]|[_-]raw$|^public_raw$|^rawarchives?$|^session_history$)", segment):
            return True
    return False


def extension(path: str) -> str:
    suffix = PurePosixPath(path).suffix.lower()
    return suffix or "[no extension]"


def top_level(path: str) -> str:
    return path.split("/", 1)[0] if "/" in path else "[root]"


def parse_local_tree(path: Path) -> dict[str, dict[str, Any]]:
    result: dict[str, dict[str, Any]] = {}
    for raw in path.read_bytes().split(b"\0"):
        if not raw:
            continue
        parts = raw.split(b"\t", 3)
        if len(parts) != 4:
            raise ValueError(f"malformed git tree record: {raw[:100]!r}")
        mode, object_type, sha, file_path = (part.decode("utf-8") for part in parts)
        if object_type != "blob":
            continue
        result[file_path] = {"mode": mode, "object_type": object_type, "sha": sha}
    return result


def parse_history(path: Path, current_paths: set[str]) -> dict[str, int]:
    newest: dict[str, int] = {}
    for chunk in path.read_bytes().split(b"\x1e"):
        if not chunk:
            continue
        lines = chunk.splitlines()
        if not lines:
            continue
        try:
            timestamp = int(lines[0].strip())
        except ValueError:
            continue
        for raw_path in lines[1:]:
            if not raw_path:
                continue
            file_path = raw_path.decode("utf-8")
            if file_path in current_paths and file_path not in newest:
                newest[file_path] = timestamp
    return newest


def iso_utc(timestamp: int | None) -> str | None:
    if timestamp is None:
        return None
    return dt.datetime.fromtimestamp(timestamp, tz=dt.timezone.utc).isoformat().replace("+00:00", "Z")


def classify_role(path: str) -> str:
    low = path.lower()
    name = PurePosixPath(path).name
    ext = extension(path)
    if is_raw_or_session_path(path):
        return "raw_or_session_metadata"
    if name in OWNER_FILENAMES:
        return "owner_entry"
    if low.startswith(".github/workflows/") or "/.github/workflows/" in low:
        return "workflow"
    if name == "package.json":
        return "package_manifest"
    if re.search(r"(^|/)(tests?|testdata|fixtures?)(/|$)", low) or name.startswith("test_"):
        return "test_or_fixture"
    if "validate" in name.lower() or "/validators/" in low:
        return "validator"
    if re.search(r"(^|/)(scripts?|tools?)(/|$)", low) and ext in CODE_EXTENSIONS:
        return "script"
    if ext in CODE_EXTENSIONS:
        return "source"
    if ext in {".md", ".txt"} or re.search(r"(^|/)(docs?|handoff)(/|$)", low):
        return "human_document"
    if re.search(r"(^|/)(artifacts?|evidence|logs?|reports?|snapshots?)(/|$)", low):
        return "generated_evidence"
    if "/data/" in low:
        return "data"
    return "other"


def default_protection(path: str, active_projects: set[str]) -> str | None:
    parts = path.split("/")
    name = parts[-1]
    if is_raw_append_only_or_session_path(path):
        return "raw_append_only_or_session_history"
    if is_raw_or_session_path(path):
        return "raw_like_content_exclusion"
    if path.startswith("FINAL_ACCEPTANCE_BUNDLE/"):
        return "current_goal_release_evidence"
    if path.startswith("HANDOFF/"):
        return "current_goal_handoff_pending_reference_audit"
    if path in {"AGENTS.md", "governance/projects.yaml", "governance/project_schema.yaml"}:
        return "root_governance_required"
    if parts[0] in active_projects and len(parts) == 2 and name in OWNER_FILENAMES:
        return "active_project_owner_entry"
    low = path.lower()
    if any(token in low for token in ("wrangler.json", "wrangler.toml", "cloudflare-public/package.json")):
        return "current_deployment_configuration"
    if path == "OpenAIDatabase/机器治理/证据与日志/final_delivery/memory_atlas_cloudflare_live_evidence.json":
        return "current_openaidatabase_live_evidence"
    if path.startswith("OpenAIDatabase/docs/acceptance/") and re.search(r"final|readiness|rollback", name.lower()):
        return "openaidatabase_final_readiness_or_rollback_evidence"
    return None


class BlobUnavailable(RuntimeError):
    pass


def git_blob_reader(
    repo: Path,
    source_commit: str,
    github_repo: str,
    expected_shas: dict[str, str],
    content_reads: set[str],
    content_sources: dict[str, str],
    unavailable_reads: set[str],
):
    cache: dict[str, bytes] = {}

    def read(path: str, *, remote_ok: bool = False) -> bytes:
        if is_raw_or_session_path(path):
            raise RuntimeError(f"raw/session content read blocked: {path}")
        if path not in cache:
            expected_sha = expected_shas[path]
            local_path = repo / path
            local_data: bytes | None = None
            if local_path.is_file():
                candidate = local_path.read_bytes()
                header = f"blob {len(candidate)}\0".encode("ascii")
                if hashlib.sha1(header + candidate).hexdigest() == expected_sha:
                    local_data = candidate
            if local_data is not None:
                cache[path] = local_data
                content_sources[path] = "worktree_blob_sha_verified"
            else:
                if not remote_ok:
                    unavailable_reads.add(path)
                    raise BlobUnavailable(path)
                encoded_path = urllib.parse.quote(path, safe="/")
                url = f"http[REDACTED_LOCAL_PATH]"
                try:
                    response = subprocess.run(
                        [
                            "curl", "--fail", "--silent", "--show-error", "--location",
                            "--max-time", "20", "--user-agent", "Codex-S02-P1-read-only-audit",
                            url,
                        ],
                        check=True,
                        capture_output=True,
                    )
                    cache[path] = response.stdout
                    header = f"blob {len(cache[path])}\0".encode("ascii")
                    actual_sha = hashlib.sha1(header + cache[path]).hexdigest()
                    if actual_sha != expected_sha:
                        raise RuntimeError(
                            f"pinned raw content SHA mismatch path={path} expected={expected_sha} actual={actual_sha}"
                        )
                    content_sources[path] = "github_raw_pinned_commit"
                except Exception as remote_error:
                    unavailable_reads.add(path)
                    raise BlobUnavailable(path) from remote_error
            content_reads.add(path)
            unavailable_reads.discard(path)
        return cache[path]

    return read

