def line_count(data: bytes) -> int:
    if not data:
        return 0
    return data.count(b"\n") + (0 if data.endswith(b"\n") else 1)


def candidate_tags(path: str, role: str) -> list[str]:
    low = path.lower()
    name = PurePosixPath(path).name.lower()
    tags: list[str] = []
    if re.search(r"(^|/)(node_modules|dist|build|coverage|__pycache__|\.pytest_cache|\.cache|\.wrangler)(/|$)", low) or name.endswith(".tsbuildinfo"):
        tags.append("tracked_build_or_cache_output")
    if re.search(r"task[ _-]?pack|taskpack|任务包", low):
        tags.append("historical_taskpack_or_task_bundle")
    documentish = role in {"human_document", "generated_evidence", "other", "data"}
    if documentish and re.search(r"(^|[/_.-])handoff([/_.-]|$)|交接", low):
        tags.append("handoff_record")
    if documentish and re.search(r"acceptance|验收", low):
        tags.append("acceptance_record")
    if documentish and re.search(r"(^|[/_.-])(stage|phase|review)([/_.-]|[0-9])|阶段|复审", low):
        tags.append("stage_phase_or_review_record")
    if role == "validator":
        tags.append("validator_consolidation_candidate")
    if documentish and (re.search(r"(^|/)(artifacts?|run_manifests?|evidence|logs?|reports?|snapshots?)(/|$)", low) or "snapshot" in name):
        tags.append("generated_evidence_or_snapshot")
    if documentish and re.search(r"(^|/)(archive|archives|backup|backups)(/|$)", low) and not is_raw_or_session_path(path):
        tags.append("historical_archive")
    if extension(path) in {".zip", ".tar", ".gz", ".tgz", ".7z"} and not is_raw_or_session_path(path):
        tags.append("tracked_delivery_archive")
    if role == "human_document" and re.search(r"report|summary|记录|报告|总结", name):
        tags.append("report_or_record_review_candidate")
    if path.startswith("OpenAIDatabase/data/derived/") or path.startswith("OpenAIDatabase/data/processed/") or path.startswith("OpenAIDatabase/data/run_logs/"):
        tags.append("openaidatabase_generated_data_surface")
    if path.startswith("OpenAIDatabase/机器治理/证据与日志/"):
        tags.append("openaidatabase_machine_evidence_surface")
    if path.startswith("OpenAIDatabase/人类可读/"):
        tags.append("openaidatabase_human_governance_surface")
    return sorted(set(tags))


def category_for(tags: set[str]) -> str:
    if "tracked_build_or_cache_output" in tags:
        return "regenerate"
    if "exact_blob_duplicate" in tags or "validator_consolidation_candidate" in tags or "report_or_record_review_candidate" in tags:
        return "merge"
    return "migrate"


def batch_for(path: str, role: str, tags: set[str]) -> str:
    low = path.lower()
    if "tracked_build_or_cache_output" in tags or "generated_evidence_or_snapshot" in tags:
        return "generated"
    if role == "validator" or role == "test_or_fixture":
        return "validation"
    if low.startswith("governance/") or "/机器治理/" in path or "/governance/" in low:
        return "governance"
    if role in {"human_document", "owner_entry"} or extension(path) in {".md", ".txt"}:
        return "documents"
    return "frontend_scripts"


