class AhoCorasick:
    def __init__(self, patterns: Iterable[str]):
        self.next: list[dict[str, int]] = [{}]
        self.fail: list[int] = [0]
        self.output: list[list[str]] = [[]]
        for pattern in patterns:
            state = 0
            for char in pattern:
                if char not in self.next[state]:
                    self.next[state][char] = self._new_state()
                state = self.next[state][char]
            self.output[state].append(pattern)
        queue: deque[int] = deque()
        for state in self.next[0].values():
            queue.append(state)
        while queue:
            parent = queue.popleft()
            for char, child in self.next[parent].items():
                queue.append(child)
                fallback = self.fail[parent]
                while fallback and char not in self.next[fallback]:
                    fallback = self.fail[fallback]
                self.fail[child] = self.next[fallback].get(char, 0)
                self.output[child].extend(self.output[self.fail[child]])

    def _new_state(self) -> int:
        self.next.append({})
        self.fail.append(0)
        self.output.append([])
        return len(self.next) - 1

    def find(self, text: str):
        state = 0
        for index, char in enumerate(text):
            while state and char not in self.next[state]:
                state = self.fail[state]
            state = self.next[state].get(char, 0)
            for pattern in self.output[state]:
                yield index - len(pattern) + 1, index + 1, pattern


