def is_boundary(text: str, start: int, end: int) -> bool:
    before = text[start - 1] if start > 0 else ""
    after = text[end] if end < len(text) else ""

    def path_char(char: str) -> bool:
        return bool(char) and (char.isalnum() or char in PATH_CHARS)

    return not path_char(before) and not path_char(after)


def normalize_link(source: str, link: str) -> str | None:
    link = urllib.parse.unquote(link.strip().strip("<>\"'"))
    if not link or link.startswith("#") or re.match(r"^[a-zA-Z][a-zA-Z0-9+.-]*:", link):
        return None
    link = link.split("#", 1)[0].split("?", 1)[0]
    if not link:
        return None
    if link.startswith("/"):
        return posixpath.normpath(link.lstrip("/"))
    return posixpath.normpath(posixpath.join(posixpath.dirname(source), link))


class ContentCache:
    def __init__(self, path: Path):
        self.path = path
        self.connection = sqlite3.connect(path)
        self.connection.execute(
            "CREATE TABLE IF NOT EXISTS blobs (sha TEXT PRIMARY KEY, content BLOB NOT NULL, source TEXT NOT NULL, bytes INTEGER NOT NULL)"
        )
        self.connection.execute(
            "CREATE TABLE IF NOT EXISTS scanned_paths (path TEXT PRIMARY KEY, sha TEXT NOT NULL, source TEXT NOT NULL)"
        )
        self.connection.commit()

    def get(self, sha: str) -> tuple[bytes, str] | None:
        row = self.connection.execute("SELECT content, source FROM blobs WHERE sha = ?", (sha,)).fetchone()
        if row is None:
            return None
        content = bytes(row[0])
        if git_blob_sha(content) != sha:
            raise RuntimeError(f"cache SHA mismatch: {sha}")
        return content, str(row[1])

    def put_many(self, values: list[tuple[str, bytes, str]]) -> None:
        self.connection.executemany(
            "INSERT OR REPLACE INTO blobs(sha, content, source, bytes) VALUES (?, ?, ?, ?)",
            [(sha, content, source, len(content)) for sha, content, source in values],
        )
        self.connection.commit()

    def replace_scanned_paths(self, values: list[tuple[str, str, str]]) -> None:
        self.connection.execute("DELETE FROM scanned_paths")
        self.connection.executemany(
            "INSERT INTO scanned_paths(path, sha, source) VALUES (?, ?, ?)",
            values,
        )
        self.connection.commit()

    def close(self) -> None:
        self.connection.close()


